import { useEffect, useState } from "react";
import {
  collection,
  doc,
  limit,
  onSnapshot,
  orderBy,
  query,
  updateDoc,
  where
} from "firebase/firestore";
import { db } from "../firebase";

function formatTimestamp(timestamp) {
  if (!timestamp?.toDate) return "Pending";
  return timestamp.toDate().toLocaleString();
}

export default function FlagsFeed() {
  const [flags, setFlags] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const flagsQuery = query(
      collection(db, "flags"),
      where("reviewed", "==", false),
      orderBy("timestamp", "desc"),
      limit(50)
    );

    const unsubscribe = onSnapshot(flagsQuery, (snapshot) => {
      setFlags(snapshot.docs.map((flagDoc) => ({ id: flagDoc.id, ...flagDoc.data() })));
      setLoading(false);
    });

    return unsubscribe;
  }, []);

  const handleMarkReviewed = async (flagId) => {
    await updateDoc(doc(db, "flags", flagId), {
      reviewed: true
    });
  };

  return (
    <section className="bg-white p-6 rounded-[20px] shadow-sm border border-[#dbe7f3]">
      <div className="flex items-center justify-between gap-4 mb-5">
        <div>
          <h2 className="text-xl font-bold text-[#122033]">Live Flag Feed</h2>
          <p className="text-sm text-[#64748b] mt-1">Real-time critical and soft-skill observations.</p>
        </div>
        <span className="text-sm font-extrabold text-[#475569] bg-[#eef4fb] px-3 py-1.5 rounded-full">
          {flags.length} open
        </span>
      </div>

      {loading ? (
        <p className="text-[#64748b]">Loading flags...</p>
      ) : flags.length === 0 ? (
        <p className="text-[#64748b]">No unreviewed flags.</p>
      ) : (
        <div className="space-y-3">
          {flags.map((flag) => {
            const isCritical = flag.type === "critical";

            return (
              <article key={flag.id} className="border border-[#e2e8f0] rounded-[16px] p-4">
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <div className="flex items-center gap-2 mb-2">
                      <span className={`px-2.5 py-1 rounded-full text-xs font-extrabold ${
                        isCritical
                          ? "bg-[#fee2e2] text-[#991b1b]"
                          : "bg-[#fef3c7] text-[#92400e]"
                      }`}>
                        {isCritical ? "Critical" : "Soft Skill"}
                      </span>
                      <span className="text-sm font-bold text-[#122033]">{flag.agentName || "Unknown Agent"}</span>
                    </div>
                    <p className="font-semibold text-[#334155]">Matched: {flag.matchedPhrase || "Unknown phrase"}</p>
                    <p className="text-sm text-[#64748b] mt-1">{formatTimestamp(flag.timestamp)}</p>
                  </div>
                  <button
                    type="button"
                    onClick={() => handleMarkReviewed(flag.id)}
                    className="shrink-0 px-3 py-2 rounded-[10px] bg-[#122033] text-white text-sm font-extrabold hover:bg-[#0f172a] transition-colors"
                  >
                    Mark Reviewed
                  </button>
                </div>
              </article>
            );
          })}
        </div>
      )}
    </section>
  );
}
